**A `debounce` function ensures that a given function is only called after a specified delay has passed since the last time it was invoked.**

```javascript
// Debounce implementation
function debounce(func, delay) {
  let timeoutId;
  return function(...args) {
    clearTimeout(timeoutId);
    timeoutId = setTimeout(() => func.apply(this, args), delay);
  };
}

// Example: Debounce a window resize handler
function onResize() {
  console.log('Window resized!');
}

window.addEventListener('resize', debounce(onResize, 500));
```

**Explanation:** Here, `onResize` will only be called 500ms after the user stops resizing the window.
